function NewsCard({ tag, title, desc, emoji }: any) {
  return (
    <div className="bg-white rounded-[3rem] overflow-hidden shadow-sm border border-[#E8F0E0] group cursor-pointer hover:shadow-xl transition-all">
      <div className="bg-[#FAF6EE] h-52 flex items-center justify-center text-7xl group-hover:scale-110 transition-transform duration-500">
        {emoji}
      </div>
      <div className="p-9 text-left">
        <span className="text-[10px] font-bold text-[#4A7C23] bg-[#E8F0E0] px-3 py-1.5 rounded-full uppercase tracking-widest">{tag}</span>
        <h4 className="font-bold text-xl mt-6 mb-3 leading-tight group-hover:text-[#4A7C23] transition-colors">{title}</h4>
        <p className="text-gray-400 text-sm leading-relaxed">{desc}</p>
      </div>
    </div>
  );
}


const News=()=>{
    return(
        <section className="py-32 text-center">
        <h2 className="font-['Cormorant_Garamond',serif] text-[64px] text-[#2D5016] mb-4 tracking-tight">Следите за новостями</h2>
        <p className="text-gray-500 mb-20 text-lg">Специальные события, новые фермеры, сезонные продукты — всё в нашем Instagram</p>
        <div className="container mx-auto px-6 max-w-7xl grid md:grid-cols-3 gap-10 mb-20">
          <NewsCard tag="Новый фермер" title="Знакомьтесь: новый сыровар" desc="Козьи сыры ручной работы теперь каждые выходные" emoji="👨‍🌾" />
          <NewsCard tag="Событие" title="Фотоотчёт с выходных" desc="Как прошли выходные на Гусь Маркет" emoji="🎉" />
          <NewsCard tag="Сезон" title="Сезонные продукты" desc="Свежие овощи и заготовки от наших фермеров" emoji="🍂" />
        </div>
        <button className="bg-[#4A7C23] text-white px-12 py-5 rounded-[1.5rem] font-bold hover:bg-[#2D5016] transition-all shadow-xl shadow-[#4A7C23]/20">
          Подписаться на Instagram
        </button>
      </section>
    )
}
export default News;